mapper.select:
/* InsrMgmtMapper.chkDupIntmInsrProd */
SELECT	COUNT(INSR_PROD_CD)
FROM	MSP_INTM_INSR_MST A
WHERE	INSR_PROD_CD = #{insrProdCd}

mapper.insert:
/* InsrMgmtMapper.regIntmInsrMst */
INSERT
INTO	MSP_INTM_INSR_MST (
		INSR_PROD_CD
		, CMPN_LMT_AMT
		, INSR_ENGG_CNT
		, INSR_TYPE_CD
		, USG_YN
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
		, SUB_LMT_YN
)
VALUES (
		#{insrProdCd}
		, #{cmpnLmtAmt}
		, #{insrEnggCnt}
		, #{insrTypeCd}
		, NVL(#{usgYn}, 'Y')
		, #{sessionUserId}
		, SYSDATE
		, #{sessionUserId}
		, SYSDATE
		, #{subLmtYn}
)

mapper.update:
/* InsrMgmtMapper.updIntmInsrMst */
UPDATE MSP_INTM_INSR_MST
SET		USG_YN = #{usgYn}
		, CMPN_LMT_AMT = #{cmpnLmtAmt}
		, INSR_ENGG_CNT = #{insrEnggCnt}
		, RVISN_ID = #{sessionUserId}
		, RVISN_DTTM = SYSDATE
		, SUB_LMT_YN = #{subLmtYn}
WHERE	INSR_PROD_CD = #{insrProdCd}

mapper.select:
/* InsrMgmtMapper.getIntmInsrMstList */ SELECT DISTINCT A.RATE_CD AS insrProdCd , A.RATE_NM AS insrProdNm , C.CMPN_LMT_AMT AS cmpnLmtAmt , A.BASE_AMT AS baseAmt , FN_GET_CODENM('CMN0248', C.INSR_ENGG_CNT) AS insrEnggCnt , C.INSR_TYPE_CD AS insrTypeCd , C.USG_YN AS usgYn , FN_GET_USRNM(C.REGST_ID) AS regstId , TO_CHAR(C.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm , FN_GET_USRNM(C.RVISN_ID) AS rvisnId , TO_CHAR(C.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm , C.SUB_LMT_YN AS subLmtYn , B.ETC6 AS ordrNo FROM MSP_RATE_MST A , CMN_GRP_CD_MST B , MSP_INTM_INSR_MST C , MSP_INTM_INSR_REL D WHERE A.RATE_CD = B.CD_VAL AND B.GRP_ID = 'CMN0247' AND A.RATE_CD = C.INSR_PROD_CD AND C.INSR_PROD_CD = D.INSR_PROD_CD(+)
AND D.RPRS_PRDT_ID = #{rprsPrdtId}
AND D.APPL_YN = #{applYn}
AND C.USG_YN = #{usgYn}
AND #{trtmDt} BETWEEN APPL_STRT_DT AND APPL_END_DT ORDER BY B.ETC6

mapper.insert:
/* InsrMgmtMapper.regIntmInsrRel */
INSERT
INTO	MSP_INTM_INSR_REL (
		INSR_PROD_CD
		, RPRS_PRDT_ID
		, APPL_YN
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
)
VALUES (
		#{insrProdCd}
		, #{rprsPrdtId}
		, DECODE(#{applYn}, 1, 'Y', 0, 'N', NVL(#{applYn}, 'Y'))
		, #{sessionUserId}
		, SYSDATE
		, #{sessionUserId}
		, SYSDATE
)

mapper.select:
/* InsrMgmtMapper.chkDupIntmInsrPrdt */
SELECT 	COUNT(INSR_PROD_CD)
FROM 	MSP_INTM_INSR_REL
WHERE 	INSR_PROD_CD =  #{insrProdCd}
AND 	RPRS_PRDT_ID = #{rprsPrdtId}

mapper.sql:
SELECT C.INSR_PROD_CD AS insrProdCd , D.RATE_NM AS insrProdNm , B.MNFCT_NM AS mnfctNm , A.RPRS_PRDT_ID AS rprsPrdtId , A.PRDT_CODE AS prdtCode , A.PRDT_NM AS prdtNm , DECODE(C.APPL_YN, 'Y', 1, 'N', 0) AS applYn , C.APPL_YN AS applYnNm , FN_GET_USRNM(C.REGST_ID) AS regstId , TO_CHAR(C.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm , FN_GET_USRNM(C.RVISN_ID) AS rvisnId , TO_CHAR(C.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm , F.SUB_LMT_YN AS subLmtYn FROM CMN_INTM_MDL A , ORG_MNFCT_MST B , MSP_INTM_INSR_REL C , MSP_RATE_MST D , CMN_GRP_CD_MST E , MSP_INTM_INSR_MST F WHERE A.RPRS_YN ='Y' AND A.MNFCT_ID = B.MNFCT_ID AND C.RPRS_PRDT_ID = A.RPRS_PRDT_ID AND C.INSR_PROD_CD = D.RATE_CD AND C.INSR_PROD_CD = E.CD_VAL AND E.GRP_ID = 'CMN0247' AND C.INSR_PROD_CD = F.INSR_PROD_CD
AND C.INSR_PROD_CD = #{insrProdCd}
AND C.APPL_YN = #{applYn}
AND A.RPRS_PRDT_ID = #{rprsPrdtId}
AND UPPER(A.PRDT_NM) LIKE '%'|| UPPER(#{prdtNm}) ||'%'
AND F.USG_YN = #{usgYn}
AND #{trtmDt} BETWEEN D.APPL_STRT_DT AND D.APPL_END_DT ORDER BY E.ETC6, A.MNFCT_ID, A.PRDT_CODE, A.PRDT_NM

mapper.update:
/* InsrMgmtMapper.updIntmInsrRel */
UPDATE 	MSP_INTM_INSR_REL
SET		APPL_YN = DECODE(#{applYn}, 1, 'Y', 0, 'N', NVL(#{applYn}, 'Y'))
		, RVISN_ID = #{sessionUserId}
		, RVISN_DTTM = SYSDATE
WHERE	INSR_PROD_CD = #{insrProdCd}
AND 	RPRS_PRDT_ID = #{rprsPrdtId}

mapper.select:
/* InsrMgmtMapper.getInsrCombo */ SELECT A.INSR_PROD_CD AS value , C.RATE_NM AS text FROM MSP_INTM_INSR_MST A , CMN_GRP_CD_MST B , MSP_RATE_MST C WHERE A.INSR_PROD_CD = B.CD_VAL AND B.GRP_ID = 'CMN0247' AND A.INSR_PROD_CD = C.RATE_CD
AND A.USG_YN = #{usgYn}
AND A.INSR_TYPE_CD = '02'
AND A.INSR_PROD_CD IN (SELECT INSR_PROD_CD FROM MSP_INTM_INSR_REL WHERE RPRS_PRDT_ID = #{rprsPrdtId} AND APPL_YN = 'Y')
ORDER BY ETC6
